public class Date {
    
    public static void main(String[] args) {
        String day  = "Thursday";
        String month = "July"; 
        int date = 18; 
        int year = 2019;
        System.out.print("American format: "); 
        System.out.print(day + ", " + month + " " + date + ", " + year); 
        System.out.print("\nEuropean format: "); 
        System.out.print(day + " " + date + " " + month + " " + year);
    }
}
